import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, icon } from 'decantr/components';

code.example:
function ContactForm({ departments, onSubmit }) {
  const { div, form, h2, p, input, label, select, option, textarea, span } = tags;
  const [name, setName] = createSignal('');
  const [email, setEmail] = createSignal('');
  const [department, setDepartment] = createSignal('');
  const [message, setMessage] = createSignal('');
  const [files, setFiles] = createSignal([]);
  const [honeypot, setHoneypot] = createSignal('');
  const [submitted, setSubmitted] = createSignal(false);
  const [loading, setLoading] = createSignal(false);
  const [errors, setErrors] = createSignal({});

  const validate = () => {
    const errs = {};
    if (!name().trim()) errs.name = 'Name is required';
    if (!email().trim()) errs.email = 'Email is required';
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email())) errs.email = 'Invalid email';
    if (!message().trim()) errs.message = 'Message is required';
    setErrors(errs);
    return Object.keys(errs).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (honeypot()) return;
    if (!validate()) return;
    setLoading(true);
    await onSubmit({ name: name(), email: email(), department: department(), message: message(), attachments: files() });
    setLoading(false);
    setSubmitted(true);
  };

  if (submitted()) {
    return div({ class: css('carbon-card _p8 _tc _maxw[600px] _mx[auto]') },
      icon('check-circle', { size: '64', class: css('_fgSuccess _mb4') }),
      h2({ class: css('_heading3 _mb2') }, 'Message Sent!'),
      p({ class: css('_fgmuted _mb6') }, "We'll get back to you within 24-48 hours."),
      Button({ variant: 'outline', onclick: () => setSubmitted(false) }, 'Send Another Message')
    );
  }

  return div({ class: css('carbon-card _p8 _maxw[600px] _mx[auto]') },
    div({ class: css('_mb6') },
      h2({ class: css('_heading3 _mb2') }, 'Get in Touch'),
      p({ class: css('_fgmuted') }, 'Have a question? We\'d love to hear from you.')
    ),
    form({ class: css('_flex _col _gap4'), onsubmit: handleSubmit },
      input({ type: 'text', name: 'website', class: css('_hidden'), value: honeypot(), oninput: (e) => setHoneypot(e.target.value), tabindex: -1, autocomplete: 'off' }),
      div({ class: css('_grid _gc1 _md:gc2 _gap4') },
        div({ class: css('_flex _col _gap1') },
          label({ class: css('_textsm _font500') }, 'Name'),
          input({ type: 'text', class: css(`carbon-input _p2 _r2 ${errors().name ? '_borderDanger' : ''}`), value: name(), oninput: (e) => setName(e.target.value) }),
          errors().name ? span({ class: css('_textsm _fgDanger') }, errors().name) : null
        ),
        div({ class: css('_flex _col _gap1') },
          label({ class: css('_textsm _font500') }, 'Email'),
          input({ type: 'email', class: css(`carbon-input _p2 _r2 ${errors().email ? '_borderDanger' : ''}`), value: email(), oninput: (e) => setEmail(e.target.value) }),
          errors().email ? span({ class: css('_textsm _fgDanger') }, errors().email) : null
        )
      ),
      departments?.length > 0 ? div({ class: css('_flex _col _gap1') },
        label({ class: css('_textsm _font500') }, 'Department'),
        select({ class: css('carbon-input _p2 _r2'), value: department(), onchange: (e) => setDepartment(e.target.value) },
          option({ value: '' }, 'Select a department...'),
          ...departments.map(d => option({ value: d.value }, d.label))
        )
      ) : null,
      div({ class: css('_flex _col _gap1') },
        label({ class: css('_textsm _font500') }, 'Message'),
        textarea({ class: css(`carbon-input _p2 _r2 _resize[vertical] ${errors().message ? '_borderDanger' : ''}`), rows: 5, value: message(), oninput: (e) => setMessage(e.target.value), placeholder: 'How can we help?' }),
        errors().message ? span({ class: css('_textsm _fgDanger') }, errors().message) : null
      ),
      div({ class: css('_flex _col _gap2') },
        label({ class: css('_textsm _font500') }, 'Attachments (optional)'),
        div({ class: css('_border _borderDashed _r2 _p4 _tc _cursor[pointer]'), onclick: () => document.getElementById('contact-files').click() },
          icon('upload', { class: css('_fgmuted _mb2') }),
          p({ class: css('_textsm _fgmuted') }, 'Click to upload or drag and drop'),
          input({ type: 'file', id: 'contact-files', multiple: true, class: css('_hidden'), onchange: (e) => setFiles([...e.target.files]) })
        ),
        files().length > 0 ? div({ class: css('_flex _gap2 _flexWrap') },
          ...files().map((f, i) => span({ class: css('_textsm _bgmuted/10 _px2 _py1 _r1') }, f.name))
        ) : null
      ),
      Button({ type: 'submit', variant: 'primary', class: css('_wfull'), disabled: loading() },
        loading() ? 'Sending...' : 'Send Message'
      )
    )
  );
}

