function CompactContactForm({ onSubmit }) {
  const { div, form, input, textarea } = tags;
  const [email, setEmail] = createSignal('');
  const [message, setMessage] = createSignal('');

  return form({ class: css('_flex _col _gap4'), onsubmit: (e) => { e.preventDefault(); onSubmit({ email: email(), message: message() }); } },
    input({ type: 'email', class: css('carbon-input _p2 _r2'), placeholder: 'Your email', value: email(), oninput: (e) => setEmail(e.target.value) }),
    textarea({ class: css('carbon-input _p2 _r2'), rows: 3, placeholder: 'Your message', value: message(), oninput: (e) => setMessage(e.target.value) }),
    Button({ type: 'submit', variant: 'primary' }, 'Send')
  );
}

